import { revalidateTag } from 'next/cache'
import { redirect } from 'next/navigation'
import { addPost } from '@/app/lib/data'

export async function createPost(formData: FormData) {
  const title = formData.get('title') as string
  const body = formData.get('body') as string

  if (!title || !body) {
    throw new Error('Title and body are required')
  }

  addPost(title, body)

  // Invalidate the "posts" cache tag so the next page load fetches fresh
  // data instead of serving stale cached content.
  revalidateTag('posts')

  // Redirect to the posts page, triggering a server-side render that will
  // call getPosts() — because the "posts" tag was just invalidated, the
  // cache miss forces a fresh data fetch before the page is served.
  redirect('/')
}
"}

